// Auto-generated from ETAT_Produit Excel — 1146 produits
import type Database from 'better-sqlite3'
import { shouldSkipProductSeed } from './userDataWipe'

export function seedProductsIfEmpty(db: Database.Database): void {
  if (shouldSkipProductSeed()) {
    console.log('[seed] Skipped product catalog — factory reset / empty catalog requested')
    return
  }

  const row = db.prepare('SELECT COUNT(*) as cnt FROM produits').get() as { cnt: number }
  if (row.cnt > 0) return // Déjà peuplé

  importDefaultProductCatalog(db)
}

/** Manual or first-install import of the built-in 1146-product catalog. */
export function importDefaultProductCatalog(db: Database.Database): number {
  const insert = db.prepare(`INSERT OR IGNORE INTO produits
    (id, code_barre, reference, nom, description, categorie, type, prix_achat, prix_vente, tva_taux, stock_actuel, stock_minimum, fournisseur, actif, created_at, updated_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?)`)

  const now = new Date().toISOString()
  const insertAll = db.transaction(() => {
    for (const p of SEED_PRODUCTS) {
      insert.run(p.id, p.code_barre, p.reference, p.nom, p.description, p.categorie, p.type, p.prix_achat, p.prix_vente, p.tva_taux, p.stock_actuel, p.stock_minimum, p.fournisseur, now, now)
    }
  })
  insertAll()
  console.log('Seeded', SEED_PRODUCTS.length, 'products')
  return SEED_PRODUCTS.length
}

